// Build API Request — v2 Contract (Ads Handler)
// FIX: Added 'const params = input.params || {}' — was missing, caused ReferenceError

const input = $input.first().json;
const domain = input.domain || input.api;
const action = input.action;
const client = input.client || $vars.DEFAULT_TEST_TENANT || 'kahuna';
const config = input.config || {};
const params = input.params || {};

const domainMap = { google_ads:'google_ads', meta_ads:'meta_ads', linkedin_ads:'linkedin_ads', amazon_ads:'amazon_ads', x_ads:'x_ads', pinterest_ads:'pinterest_ads', reddit_ads:'reddit_ads', google_ad_manager:'google_ad_manager', microsoft_ads:'microsoft_ads' };
const apiKey = domainMap[domain] || domain;

const serviceBody = Object.assign({}, params);
['customerId','customer_id','mccId','devToken','date_range','_handler_secret'].forEach(k => delete serviceBody[k]);

const liAcctId = params.ad_account_id || $vars['LINKEDIN_AD_ACCOUNT_ID'] || '';
const liNow = new Date();
const liAnalyticsUrl = `/adAnalytics?q=analytics&pivot=${params.pivot||'CAMPAIGN'}&dateRange=(start:(year:${params.startYear||liNow.getFullYear()},month:${params.startMonth||1},day:1),end:(year:${liNow.getFullYear()},month:${liNow.getMonth()+1},day:${liNow.getDate()}))&timeGranularity=${params.timeGranularity||'MONTHLY'}&fields=${params.fields||'impressions,clicks,costInLocalCurrency'}&accounts=List(urn%3Ali%3AsponsoredAccount%3A${liAcctId})`;

const endpoints = {
  google_ads: { base_url: config.base_url||'https://googleads.googleapis.com', actions: {
    campaigns:{method:'POST',path:`/v23.1/customers/${params.customerId||params.customer_id||'{customer_id}'}/googleAds:search`,body:{query:params.gaql||`SELECT campaign.id,campaign.name,campaign.status,metrics.impressions,metrics.clicks,metrics.cost_micros FROM campaign WHERE segments.date DURING ${params.date_range||'LAST_7_DAYS'}`}},
    ad_groups:{method:'POST',path:`/v23.1/customers/${params.customerId||params.customer_id||'{customer_id}'}/googleAds:search`,body:{query:params.gaql||`SELECT ad_group.id,ad_group.name,ad_group.status,ad_group.campaign,metrics.impressions,metrics.clicks FROM ad_group WHERE segments.date DURING ${params.date_range||'LAST_7_DAYS'}`}},
    keywords:{method:'POST',path:`/v23.1/customers/${params.customerId||params.customer_id||'{customer_id}'}/googleAds:search`,body:{query:params.gaql||`SELECT ad_group_criterion.keyword.text,ad_group_criterion.keyword.match_type,metrics.impressions,metrics.clicks,metrics.cost_micros FROM keyword_view WHERE segments.date DURING ${params.date_range||'LAST_7_DAYS'}`}},
    custom_query:{method:'POST',path:`/v23.1/customers/${params.customerId||params.customer_id||'{customer_id}'}/googleAds:search`,body:{query:params.gaql||params.query}},
    mutate:{method:'POST',path:`/v23.1/customers/${params.customerId||params.customer_id||'{customer_id}'}/googleAds:mutate`,body:{mutateOperations:params.operations||[]}},
    benchmarks:{method:'POST',path:`/v23.1/customers/${params.customerId||params.customer_id||'{customer_id}'}:generateBenchmarksMetrics`,body:serviceBody},
    audience_definition:{method:'POST',path:`/v23.1/customers/${params.customerId||params.customer_id||'{customer_id}'}:generateAudienceDefinition`,body:serviceBody},
    creator_insights:{method:'POST',path:`/v23.1/customers/${params.customerId||params.customer_id||'{customer_id}'}:generateCreatorInsights`,body:serviceBody}
  }},
  meta_ads: { base_url: config.base_url||'https://graph.facebook.com/v25.0', actions: {
    campaigns:{method:'GET',path:`/act_${params.ad_account_id||$vars.META_ADS_ACCOUNT_ID||'{ad_account_id}'}/campaigns`,body:null},
    ad_sets:{method:'GET',path:`/act_${params.ad_account_id||$vars.META_ADS_ACCOUNT_ID||'{ad_account_id}'}/adsets`,body:null},
    insights:{method:'GET',path:`/act_${params.ad_account_id||$vars.META_ADS_ACCOUNT_ID||'{ad_account_id}'}/insights`,body:null}
  }},
  amazon_ads: { base_url: config.base_url||'https://advertising-api.amazon.com', actions: {
    list_profiles:{method:'GET',path:'/v2/profiles',body:null}, campaigns:{method:'GET',path:'/v2/sp/campaigns',body:null},
    ad_groups:{method:'GET',path:'/v2/sp/adGroups',body:null}, keywords:{method:'GET',path:'/v2/sp/keywords',body:null},
    report:{method:'POST',path:'/reporting/reports',body:params.report_config||{}}
  }},
  pinterest_ads: { base_url: config.base_url||'https://api.pinterest.com/v5', actions: {
    ad_accounts:{method:'GET',path:'/ad_accounts',body:null},
    campaigns:{method:'GET',path:`/ad_accounts/${params.ad_account_id||'{ad_account_id}'}/campaigns`,body:null},
    ad_groups:{method:'GET',path:`/ad_accounts/${params.ad_account_id||'{ad_account_id}'}/ad_groups`,body:null},
    analytics:{method:'GET',path:`/ad_accounts/${params.ad_account_id||'{ad_account_id}'}/campaigns/analytics`,body:null}
  }},
  x_ads: { base_url: config.base_url||'https://ads-api.x.com/12', actions: {
    accounts:{method:'GET',path:'/accounts',body:null},
    campaigns:{method:'GET',path:`/accounts/${params.account_id||'{account_id}'}/campaigns`,body:null},
    line_items:{method:'GET',path:`/accounts/${params.account_id||'{account_id}'}/line_items`,body:null},
    stats:{method:'GET',path:`/stats/accounts/${params.account_id||'{account_id}'}`,body:null}
  }},
  reddit_ads: { base_url: config.base_url||'https://ads-api.reddit.com/api/v2.0', actions: {
    accounts:{method:'GET',path:'/accounts',body:null},
    campaigns:{method:'GET',path:`/accounts/${params.account_id||'{account_id}'}/campaigns`,body:null},
    ad_groups:{method:'GET',path:`/accounts/${params.account_id||'{account_id}'}/adgroups`,body:null},
    report:{method:'GET',path:`/accounts/${params.account_id||'{account_id}'}/reports`,body:null}
  }},
  google_ad_manager: { base_url: config.base_url||'https://admanager.googleapis.com/v1', actions: {
    networks:{method:'GET',path:'/networks',body:null},
    orders:{method:'GET',path:`/networks/${params.network_code||'{network_code}'}/orders`,body:null},
    line_items:{method:'GET',path:`/networks/${params.network_code||'{network_code}'}/lineItems`,body:null},
    ad_units:{method:'GET',path:`/networks/${params.network_code||'{network_code}'}/adUnits`,body:null},
    report:{method:'POST',path:`/networks/${params.network_code||'{network_code}'}/reports:run`,body:params.report_body||{}}
  }},
  microsoft_ads: { base_url:'https://campaign.api.bingads.microsoft.com', actions: {
    campaigns:{method:'POST',path:'/CampaignManagement/v13/Campaigns/QueryByAccountId',body:{AccountId:params.account_id||params.AccountId||''}},
    ad_groups:{method:'POST',path:'/CampaignManagement/v13/AdGroups/QueryByCampaignId',body:{CampaignId:params.campaign_id||params.CampaignId||''}},
    ads:{method:'POST',path:'/CampaignManagement/v13/Ads/QueryByAdGroupId',body:{AdGroupId:params.ad_group_id||params.AdGroupId||''}},
    keywords:{method:'POST',path:'/CampaignManagement/v13/Keywords/QueryByAdGroupId',body:{AdGroupId:params.ad_group_id||params.AdGroupId||''}},
    accounts:{method:'POST',path:'/CustomerManagement/v13/Accounts/Search',body:{Predicate:params.predicate||null,Ordering:null,PageInfo:{Index:0,Size:100}}},
    report:{method:'POST',path:'/Reporting/v13/GenerateReport/Submit',body:params.report_request||{}}
  }},
  linkedin_ads: { base_url: config.base_url||'https://api.linkedin.com/rest', actions: {
    campaigns:{method:'GET',path:`/adAccounts/${params.ad_account_id||$vars['LINKEDIN_AD_ACCOUNT_ID']}/adCampaigns?q=search&search=(status:(values:List(${params.status||'ACTIVE'})))`,body:null,query:{}},
    analytics:{method:'GET',path:liAnalyticsUrl,body:null,query:{}},
    creatives:{method:'GET',path:`/adAccounts/${params.ad_account_id||$vars['LINKEDIN_AD_ACCOUNT_ID']}/creatives`,body:null,query:{q:'criteria'}},
    revenue_attribution:{method:'GET',path:'/adAnalytics',body:null,query:{q:'attributedRevenueMetrics',accounts:`List(urn:li:sponsoredAccount:${params.ad_account_id||$vars['LINKEDIN_AD_ACCOUNT_ID']})`}},
    predictive_audiences:{method:'POST',path:'/predictiveAudiences',body:params},
    company_intelligence:{method:'GET',path:'/companyIntelligence',body:null}
  }}
};

const apiConfig = endpoints[apiKey];
if (!apiConfig) return [{json:{ok:false,data:null,error:{type:'handler_error',message:`Ads handler: unknown domain '${domain}'. Supported: ${Object.keys(endpoints).join(', ')}`,details:{domain}},_v2:{domain,action,client,mode:input.mode,meta:input.meta}}}];

const endpoint = apiConfig.actions[action];
if (!endpoint) return [{json:{ok:false,data:null,error:{type:'handler_error',message:`Ads handler: unknown action '${action}' for ${domain}. Available: ${Object.keys(apiConfig.actions).join(', ')}`,details:{domain,action}},_v2:{domain,action,client,mode:input.mode,meta:input.meta}}}];

// === DOMAIN-SPECIFIC HEADERS (config-driven from tenant_metadata params) ===
const headers = {};
if (apiKey==='google_ads') {
  headers['developer-token'] = params.developer_token || $vars.GOOGLE_ADS_DEVELOPER_TOKEN || '';
  headers['login-customer-id'] = params.login_customer_id || $vars.GOOGLE_ADS_LOGIN_CUSTOMER_ID || '';
}
if (apiKey==='microsoft_ads') { headers['DeveloperToken']=params.developer_token||$vars['MICROSOFT_ADS_DEVELOPER_TOKEN']||''; headers['CustomerId']=params.customer_id||$vars['MICROSOFT_ADS_CUSTOMER_ID']||''; headers['AccountId']=params.account_id||$vars['MICROSOFT_ADS_ACCOUNT_ID']||''; }
if (apiKey==='linkedin_ads') { headers['Linkedin-Version']='202602'; headers['X-Restli-Protocol-Version']='2.0.0'; headers['X-RestLi-Method']='FINDER'; }

const queryString = endpoint.query && Object.keys(endpoint.query).length ? '?'+Object.entries(endpoint.query).filter(([,v])=>v!==undefined&&v!==null&&v!=='').map(([k,v])=>`${encodeURIComponent(k)}=${encodeURIComponent(v)}`).join('&') : '';

return [{json:{method:endpoint.method,url:apiConfig.base_url+endpoint.path+queryString,query:{},body:endpoint.body||{},headers,_v2:{domain,action,client,mode:input.mode,meta:input.meta}}}];
